patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 610e4904a80a..acf8f0d91416 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -2941,6 +2941,16 @@ void InnerLoopVectorizer::fixVectorizedLoop(VPTransformState &State) {
   PSE.getSE()->forgetLoop(OrigLoop);
   PSE.getSE()->forgetBlockAndLoopDispositions();

+  // Vectorizing the loop can change dominance/availability of values and
+  // therefore invalidate SCEVs computed at the scope of other loops (e.g.,
+  // trip/exit counts that reference values from the transformed loop). To avoid
+  // reusing stale SCEVs, conservatively invalidate SCEV information for all
+  // loops in the function.
+  if (LI) {
+    for (Loop *L : LI->getLoopsInPreorder())
+      PSE.getSE()->forgetLoop(L);
+  }
+
   // After vectorization, the exit blocks of the original loop will have
   // additional predecessors. Invalidate SCEVs for the exit phis in case SE
   // looked through single-entry phis.

